content.content:
 1→$color-background: #191919;
 2→$color-surface: #232325;
 3→$color-surface-hover: #2a2a2d;
 4→$color-border: #2f2f32;
 5→$color-text-primary: #e5e5ea;
 6→$color-text-secondary: #98989d;
 7→$color-text-tertiary: #6e6e73;
 8→$color-accent: #007aff;
 9→$color-accent-hover: #0a84ff;
10→$color-destructive: #ff453a;
11→$color-success: #30d158;
12→$color-surface-footer: #1c1c1e;
13→$color-text-on-accent: #ffffff;
14→$color-text-on-accent-secondary: rgba(255, 255, 255, 0.7);
15→$color-kbd-background: rgba(255, 255, 255, 0.08);
16→$color-kbd-background-on-accent: rgba(255, 255, 255, 0.15);
17→$color-kbd-border-on-accent: rgba(255, 255, 255, 0.25);
18→$color-selection-background: rgba($color-accent, 0.1);
19→$color-code-background: rgba(255, 255, 255, 0.06);
20→$color-tag-background: rgba(255, 255, 255, 0.1);
21→
22→$font-family-mono: 'SF Mono', SFMono-Regular, ui-monospace, Menlo, monospace;
23→
24→$font-weight-regular: 400;
25→$font-weight-medium: 500;
26→$font-weight-semibold: 600;
27→
28→$space-half: 2px;
29→$space-1: 4px;
30→$space-2: 8px;
31→$space-3: 12px;
32→$space-4: 16px;
33→$space-5: 20px;
34→$space-6: 24px;
35→$space-7: 28px;
36→$space-8: 32px;
37→
38→$radius-sm: 4px;
39→$radius-md: 8px;
40→$radius-lg: 12px;
41→$radius-xl: 16px;
42→$radius-window: 18px;
43→
44→$shadow-window:
45→  0 24px 80px rgba(0, 0, 0, 0.55),
46→  0 2px 12px rgba(0, 0, 0, 0.35);
47→$shadow-popover:
48→  0 12px 32px rgba(0, 0, 0, 0.45),
49→  0 1px 6px rgba(0, 0, 0, 0.25);
50→
51→$font-family:
52→  'Inter',
53→  -apple-system,
54→  BlinkMacSystemFont,
55→  'SF Pro Text',
56→  'Segoe UI',
57→  Roboto,
58→  Helvetica,
59→  Arial,
60→  sans-serif;
61→
62→$font-xs: 11px;
63→$font-sm: 12px;
64→$font-md: 13px;
65→$font-base: 14px;
66→$font-lg: 15px;
67→$font-search: 16px;
68→$font-xl: 20px;
69→
70→$search-bar-height: 56px;
71→$list-item-height: 40px;
72→$action-panel-height: 40px;
73→$size-grid-icon: 64px;
74→
75→$transition-fast: 80ms;
76→$transition-normal: 150ms;
77→$transition-slow: 250ms;
78→

 1→@use '../../styles/tokens' as *;
 2→
 3→.command-palette-overlay {
 4→  position: fixed;
 5→  inset: 0;
 6→  display: flex;
 7→  align-items: flex-start;
 8→  justify-content: center;
 9→  padding-top: 15vh;
10→}
11→
12→.command-palette {
13→  position: relative;
14→  width: 750px;
15→  max-width: calc(100vw - $space-6 * 2);
16→  max-height: 500px;
17→  display: flex;
18→  flex-direction: column;
19→  background: linear-gradient(
20→    180deg,
21→    rgba($color-background, 0.4) 0%,
22→    rgba($color-surface, 0.4) 100%
23→  );
24→  backdrop-filter: blur(72px) saturate(200%);
25→  -webkit-backdrop-filter: blur(72px) saturate(200%);
26→  border-radius: $radius-window;
27→  border: 1px solid rgba($color-text-primary, 0.2);
28→  border-style: inset;
29→  box-shadow: $shadow-window;
30→  overflow: hidden;
31→  animation: palette-appear $transition-slow ease-out both;
32→}
33→
34→.command-palette__body {
35→  display: flex;
36→  flex: 1;
37→  min-height: 0;
38→  overflow: hidden;
39→}
40→
41→.command-palette__list-container {
42→  display: flex;
43→  flex-direction: column;
44→  flex: 1;
45→  min-width: 0;
46→  overflow: hidden;
47→
48→  .command-palette__body--has-detail & {
49→    flex: 0 0 40%;
50→  }
51→}
52→

 1→@use '../../styles/tokens' as *;
 2→
 3→.search-bar {
 4→  display: flex;
 5→  align-items: center;
 6→  height: $search-bar-height;
 7→  padding: 0 $space-4;
 8→  border-bottom: 1px solid $color-border;
 9→  gap: $space-3;
10→}
11→
12→.search-bar__icon {
13→  flex-shrink: 0;
14→  color: $color-text-tertiary;
15→}
16→
17→.search-bar__breadcrumbs {
18→  display: flex;
19→  align-items: center;
20→  flex-shrink: 0;
21→  gap: $space-half;
22→}
23→
24→.search-bar__breadcrumb {
25→  display: inline-flex;
26→  align-items: center;
27→  padding: $space-half $space-2;
28→  border: none;
29→  border-radius: $radius-sm;
30→  background: $color-surface-hover;
31→  font-family: $font-family;
32→  font-size: $font-sm;
33→  color: $color-text-secondary;
34→  cursor: pointer;
35→  white-space: nowrap;
36→  transition: background-color $transition-fast ease;
37→
38→  &:hover {
39→    background: $color-border;
40→  }
41→
42→  &:focus-visible {
43→    outline: 2px solid $color-accent;
44→    outline-offset: -1px;
45→  }
46→
47→  &--current {
48→    cursor: default;
49→
50→    &:hover {
51→      background: $color-surface-hover;
52→    }
53→  }
54→}
55→
56→.search-bar__breadcrumb-chevron {
57→  flex-shrink: 0;
58→  color: $color-text-tertiary;
59→}
60→
61→.search-bar__input {
62→  flex: 1;
63→  min-width: 0;
64→  height: 100%;
65→  border: none;
66→  outline: none;
67→  background: transparent;
68→  font-family: $font-family;
69→  font-size: $font-search;
70→  color: $color-text-primary;
71→  caret-color: $color-accent;
72→
73→  &::placeholder {
74→    color: $color-text-tertiary;
75→  }
76→}
77→

 1→@use '../../styles/tokens' as *;
 2→
 3→.action-panel {
 4→  position: relative;
 5→  display: flex;
 6→  align-items: center;
 7→  justify-content: space-between;
 8→  height: $action-panel-height;
 9→  padding: 0 $space-2;
10→  border-top: 1px solid $color-border;
11→  background-color: $color-surface-footer;
12→  border-radius: 0 0 $radius-window $radius-window;
13→  flex-shrink: 0;
14→  animation: action-panel-slide-up $transition-slow ease-out both;
15→  animation-delay: $transition-fast;
16→
17→  &__primary,
18→  &__secondary {
19→    display: flex;
20→    align-items: center;
21→    gap: $space-3;
22→  }
23→
24→  &__action {
25→    display: flex;
26→    align-items: center;
27→    gap: $space-2;
28→    background: none;
29→    border: none;
30→    padding: 0;
31→    cursor: pointer;
32→    color: $color-text-secondary;
33→    font-family: $font-family;
34→    font-size: $font-sm;
35→    line-height: 1;
36→    transition: color $transition-fast ease;
37→
38→    &:hover {
39→      color: $color-text-primary;
40→    }
41→
42→    &:focus-visible {
43→      outline: 2px solid $color-accent;
44→      outline-offset: 2px;
45→      border-radius: $radius-sm;
46→    }
47→  }
48→
49→  &__label {
50→    white-space: nowrap;
51→  }
52→
53→  &__shortcut {
54→    display: inline-flex;
55→    align-items: center;
56→    gap: $space-half;
57→  }
58→}
59→

 1→@use '../../styles/tokens' as *;
 2→
 3→.actions-dropdown {
 4→  position: absolute;
 5→  bottom: calc($action-panel-height + $space-2);
 6→  right: $space-2;
 7→  min-width: 220px;
 8→  max-height: 300px;
 9→  overflow-y: auto;
10→  background-color: $color-surface;
11→  border: 1px solid $color-border;
12→  border-radius: $radius-lg;
13→  box-shadow: $shadow-popover;
14→  padding: $space-1;
15→  z-index: 100;
16→  animation: dropdown-appear $transition-normal ease-out both;
17→}
18→
19→.actions-dropdown__item {
20→  display: flex;
21→  align-items: center;
22→  justify-content: space-between;
23→  gap: $space-4;
24→  width: 100%;
25→  padding: $space-2 $space-3;
26→  background: none;
27→  border: none;
28→  border-radius: $radius-md;
29→  cursor: pointer;
30→  color: $color-text-primary;
31→  font-family: $font-family;
32→  font-size: $font-sm;
33→  line-height: 1;
34→  text-align: left;
35→  transition: background-color $transition-fast ease;
36→
37→  &:hover,
38→  &--active {
39→    background-color: $color-accent;
40→    color: $color-text-on-accent;
41→
42→    .actions-dropdown__shortcut .kbd__key {
43→      background-color: $color-kbd-background-on-accent;
44→      border-color: $color-kbd-border-on-accent;
45→      color: $color-text-on-accent-secondary;
46→    }
47→  }
48→
49→  &:focus-visible {
50→    outline: 2px solid $color-accent;
51→    outline-offset: -2px;
52→    border-radius: $radius-md;
53→  }
54→}
55→
56→.actions-dropdown__label {
57→  white-space: nowrap;
58→}
59→
60→.actions-dropdown__shortcut {
61→  display: inline-flex;
62→  align-items: center;
63→  flex-shrink: 0;
64→}
65→
66→@keyframes dropdown-appear {
67→  from {
68→    opacity: 0;
69→    transform: scale(0.96) translateY(4px);
70→  }
71→
72→  to {
73→    opacity: 1;
74→    transform: scale(1) translateY(0);
75→  }
76→}
77→

